1	import type { LayoutLoad } from './$types'
2	import { createClient } from '$lib/gql/client'
3	import { gql } from 'graphql-request'
4	
5	const WORKERS_QUERY = gql`
6		query WorkersByProject($projectID: String!) {
7			workersByProject(projectID: $projectID, first: 50) {
8				edges {
9					node {
10						id
11						kind
12						state
13						status
14						harness
15						model
16						currentBead
17						attempts
18						successes
19						failures
20						startedAt
21					}
22					cursor
23				}
24				pageInfo {
25					hasNextPage
26					endCursor
27				}
28				totalCount
29			}
30			queueAndWorkersSummary(projectId: $projectID) {
31				maxCount
32			}
33		}
34	`
35	
36	interface WorkerNode {
37		id: string
38		kind: string
39		state: string
40		status: string | null
41		harness: string | null
42		model: string | null
43		currentBead: string | null
44		attempts: number | null
45		successes: number | null
46		failures: number | null
47		startedAt: string | null
48	}
49	
50	interface WorkerEdge {
51		node: WorkerNode
52		cursor: string
53	}
54	
55	interface WorkerConnection {
56		edges: WorkerEdge[]
57		pageInfo: { hasNextPage: boolean; endCursor: string | null }
58		totalCount: number
59	}
60	
61	interface WorkersResult {
62		workersByProject: WorkerConnection
63		queueAndWorkersSummary: { maxCount: number | null }
64	}
65	
66	export const load: LayoutLoad = async ({ params, fetch }) => {
67		const client = createClient(fetch as unknown as typeof globalThis.fetch)
68		const data = await client.request<WorkersResult>(WORKERS_QUERY, {
69			projectID: params.projectId
70		})
71		return {
72			projectId: params.projectId,
73			workers: data.workersByProject,
74			maxCount: data.queueAndWorkersSummary?.maxCount ?? null
75		}
76	}
77

1	<script lang="ts">
2		import type { LayoutData } from './$types';
3		import type { Snippet } from 'svelte';
4		import { goto, invalidateAll } from '$app/navigation';
5		import { page } from '$app/stores';
6		import { createClient } from '$lib/gql/client';
7		import { subscribeWorkerProgress } from '$lib/gql/subscriptions';
8		import { gql } from 'graphql-request';
9	
10		let { data, children }: { data: LayoutData; children: Snippet } = $props();
11	
12		const START_WORKER_MUTATION = gql`
13			mutation StartWorker($input: StartWorkerInput!) {
14				startWorker(input: $input) {
15					id
16					state
17					kind
18				}
19			}
20		`;
21	
22		const STOP_WORKER_MUTATION = gql`
23			mutation StopWorker($id: ID!) {
24				stopWorker(id: $id) {
25					id
26					state
27					kind
28				}
29			}
30		`;
31	
32		// + Add worker dispatches a default-spec drain worker (ddx-b6cf025c). The
33		// server honours .ddx/config.yaml workers.default_spec + workers.max_count.
34		const ADD_WORKER_MUTATION = gql`
35			mutation AddDrainWorker($projectId: String!) {
36				workerDispatch(kind: "execute-loop", projectId: $projectId) {
37					id
38					state
39					kind
40				}
41			}
42		`;
43	
44		// Live phase overrides from workerProgress subscription (workerID -> phase)
45		let livePhaseOverrides = $state<Map<string, string>>(new Map());
46		let showStartForm = $state(false);
47		let starting = $state(false);
48		let stoppingId = $state<string | null>(null);
49		let actionError = $state<string | null>(null);
50		let harness = $state('');
51		let profile = $state('smart');
52		let effort = $state('medium');
53		let labelFilter = $state('');
54		let adding = $state(false);
55		let removing = $state(false);
56	
57		// Drain workers: count of running execute-loop workers.
58		const runningDrainCount = $derived(
59			data.workers.edges.filter(
60				(e) => e.node.state === 'running' && e.node.kind === 'execute-loop'
61			).length
62		);
63	
64		// workers.max_count safety rail (ddx-b6cf025c). Null = no cap configured.
65		const maxCount = $derived(data.maxCount);
66		const atMaxCount = $derived(
67			typeof maxCount === 'number' && maxCount >= 0 && runningDrainCount >= maxCount
68		);
69		const addDisabled = $derived(adding || atMaxCount);
70		const addTooltip = $derived(
71			atMaxCount ? 'at workers.max_count limit' : 'Add a general-purpose drain worker'
72		);
73	
74		// Subscribe to progress events for all running workers
75		$effect(() => {
76			const runningIds = data.workers.edges
77				.filter((e) => e.node.state === 'running')
78				.map((e) => e.node.id);
79	
80			livePhaseOverrides = new Map();
81	
82			const disposes = runningIds.map((workerID) =>
83				subscribeWorkerProgress(workerID, (evt) => {
84					const next = new Map(livePhaseOverrides);
85					next.set(evt.workerID, evt.phase);
86					livePhaseOverrides = next;
87				})
88			);
89	
90			return () => disposes.forEach((d) => d());
91		});
92	
93		// The currently open worker (from child route params)
94		let activeWorker = $derived(($page.params as Record<string, string>)['workerId'] ?? null);
95	
96		function openWorker(workerId: string) {
97			const p = $page.params as Record<string, string>;
98			goto(`/nodes/${p['nodeId']}/projects/${p['projectId']}/workers/${workerId}`);
99		}
100	
101		function sessionsHref(): string {
102			const p = $page.params as Record<string, string>;
103			return `/nodes/${p['nodeId']}/projects/${p['projectId']}/sessions`;
104		}
105	
106		function errorText(err: unknown): string {
107			return err instanceof Error ? err.message : 'Worker action failed.';
108		}
109	
110		async function startWorker() {
111			actionError = null;
112			if (!profile.trim() || !effort.trim()) {
113				actionError = 'Profile and effort are required.';
114				return;
115			}
116			starting = true;
117			try {
118				const client = createClient(fetch);
119				await client.request(START_WORKER_MUTATION, {
120					input: {
121						projectId: data.projectId,
122						harness: harness.trim() || null,
123						profile: profile.trim(),
124						effort: effort.trim(),
125						labelFilter: labelFilter.trim() || null
126					}
127				});
128				showStartForm = false;
129				harness = '';
130				labelFilter = '';
131				await invalidateAll();
132			} catch (err) {
133				actionError = errorText(err);
134			} finally {
135				starting = false;
136			}
137		}
138	
139		async function addDrainWorker() {
140			actionError = null;
141			adding = true;
142			try {
143				const client = createClient(fetch);
144				await client.request(ADD_WORKER_MUTATION, { projectId: data.projectId });
145				await invalidateAll();
146			} catch (err) {
147				actionError = errorText(err);
148			} finally {
149				adding = false;
150			}
151		}
152	
153		async function removeDrainWorker() {
154			actionError = null;
155			// Find the oldest running execute-loop worker (AC #4: "stops the oldest-
156			// running drain worker"). data.workers is sorted newest-first, so the
157			// last matching edge is oldest.
158			const runningDrain = data.workers.edges
159				.filter((e) => e.node.state === 'running' && e.node.kind === 'execute-loop')
160				.map((e) => e.node);
161			const target = runningDrain[runningDrain.length - 1];
162			if (!target) return;
163			if (!window.confirm(`Stop worker ${target.id}?`)) return;
164			removing = true;
165			try {
166				const client = createClient(fetch);
167				await client.request(STOP_WORKER_MUTATION, { id: target.id });
168				await invalidateAll();
169			} catch (err) {
170				actionError = errorText(err);
171			} finally {
172				removing = false;
173			}
174		}
175	
176		async function stopWorker(event: MouseEvent, workerId: string) {
177			event.stopPropagation();
178			actionError = null;
179			if (!window.confirm(`Stop worker ${workerId}?`)) return;
180			stoppingId = workerId;
181			try {
182				const client = createClient(fetch);
183				await client.request(STOP_WORKER_MUTATION, { id: workerId });
184				await invalidateAll();
185			} catch (err) {
186				actionError = errorText(err);
187			} finally {
188				stoppingId = null;
189			}
190		}
191	
192		function stateClass(state: string): string {
193			switch (state) {
194				case 'running':
195					return 'text-status-running';
196				case 'idle':
197					return 'text-status-open';
198				case 'stopped':
199					return 'text-fg-muted dark:text-dark-fg-muted';
200				case 'error':
201					return 'text-status-failed';
202				default:
203					return 'text-fg-muted dark:text-dark-fg-muted';
204			}
205		}
206	</script>
