153	async function mockGraphQL(page: import('@playwright/test').Page, workers = WORKERS) {
154		await page.route('/graphql', async (route) => {
155			const body = route.request().postDataJSON() as { query: string };
156	
157			if (body.query.includes('NodeInfo')) {
158				await route.fulfill({
159					status: 200,
160					contentType: 'application/json',
161					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
162				});
163			} else if (body.query.includes('Projects')) {
164				await route.fulfill({
165					status: 200,
166					contentType: 'application/json',
167					body: JSON.stringify({
168						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
169					})
170				});
171			} else if (body.query.includes('WorkersByProject')) {
172				await route.fulfill({
173					status: 200,
174					contentType: 'application/json',
175					body: JSON.stringify({ data: makeWorkersResponse(workers) })
176				});
177			} else if (body.query.includes('WorkerDetail')) {
178				await route.fulfill({
179					status: 200,
180					contentType: 'application/json',
181					body: JSON.stringify({ data: { worker: WORKER_DETAIL } })
182				});
183			} else if (body.query.includes('WorkerLog')) {
184				await route.fulfill({
185					status: 200,
186					contentType: 'application/json',
187					body: JSON.stringify({ data: { workerLog: WORKER_LOG } })
188				});
189			} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
190				await route.fulfill({
191					status: 200,
192					contentType: 'application/json',
193					body: JSON.stringify({ data: makeSessionsResponse() })
194				});
195			} else if (body.query.includes('WorkerProgress')) {
196				// Subscriptions are handled over WebSocket; pass through
197				await route.continue();
198			} else {
199				await route.continue();
200			}
201		});
202	}
